def gen(rng, size):
    def t():
        h = rng.randint(0, 23)
        m = rng.randint(0, 59)
        return '%02d:%02d' % (h, m)
    def ev():
        a, b = t(), t()
        if a > b:
            a, b = b, a
        return [a, b]
    return [ev(), ev()]

