class Solution:
    def haveConflict(self, event1, event2):
        def mins(s):
            return int(s[:2]) * 60 + int(s[3:])
        s1, e1 = mins(event1[0]), mins(event1[1])
        s2, e2 = mins(event2[0]), mins(event2[1])
        return max(s1, s2) <= min(e1, e2)

